func TestRestockPredictWithHistory(t *testing.T) {
	tmp, err := os.CreateTemp("", "restock_test2_*.db")
	if err != nil {
		t.Fatal(err)
	}
	tmp.Close()
	defer os.Remove(tmp.Name())

	db, err := store.Open(tmp.Name())
	if err != nil {
		t.Fatal(err)
	}
	defer db.Close()

	// Insert two snapshots at different times
	items1 := []store.CartSnapshotItem{
		{ID: "101", Name: "Arroz 5KG", Qty: 2, Price: 18.99},
		{ID: "102", Name: "Feijao 1KG", Qty: 3, Price: 7.99},
	}
	items2 := []store.CartSnapshotItem{
		{ID: "101", Name: "Arroz 5KG", Qty: 2, Price: 18.99},
		{ID: "102", Name: "Feijao 1KG", Qty: 3, Price: 7.99},
	}

	_, err = store.SnapshotCart(db.DB(), items1)
	if err != nil {
		t.Fatal(err)
	}
	// Simulate a later snapshot by inserting directly with a past timestamp
	_, err = db.DB().Exec(
		`INSERT INTO cart_snapshots (taken_at, items_json) VALUES (?, ?)`,
		time.Now().Add(-7*24*time.Hour).UTC().Format(time.RFC3339),
		`[{"id":"101","name":"Arroz 5KG","qty":2,"price":18.99},{"id":"102","name":"Feijao 1KG","qty":3,"price":7.99}]`,
	)
	if err != nil {
		t.Fatal(err)
	}
	_, err = store.SnapshotCart(db.DB(), items2)
	if err != nil {
		t.Fatal(err)
	}

	count, err := store.CountCartSnapshots(db.DB())
	if err != nil {
		t.Fatal(err)
	}
	if count < 2 {
		t.Fatalf("expected >= 2 snapshots, got %d", count)
	}

	// Fetch and verify we can read back snapshots
	snaps, err := store.LatestCartSnapshots(db.DB(), 10)
	if err != nil {
		t.Fatal(err)
	}
	if len(snaps) < 2 {
		t.Fatalf("expected >= 2 snapshots, got %d", len(snaps))
	}
	if len(snaps[0].Items) != 2 {
		t.Errorf("expected 2 items in latest snapshot, got %d", len(snaps[0].Items))
	}
}
